// -----------------------------------------------------------------------------

Dungeon::Dungeon()                                      : Scene { {0.0f}, nullptr   } {}
Dungeon::Dungeon(Vector2 origin, const char *bgHexCode) : Scene { origin, bgHexCode } {}

Dungeon::~Dungeon() { shutdown(); }

void Dungeon::initialise()
{
    mGameState.nextSceneID = 0;

    std::map<Animation, std::vector<int>> animationAtlas =
    {
        { ANIM_DOWN,       {  0,  1 } },
        { ANIM_DOWN_LEFT,  {  2,  3 } },
        { ANIM_LEFT,       {  4,  5 } },
        { ANIM_UP_LEFT,    {  6,  7 } },
        { ANIM_UP,         {  8,  9 } },
        { ANIM_UP_RIGHT,   { 10, 11 } },
        { ANIM_RIGHT,      { 12, 13 } },
        { ANIM_DOWN_RIGHT, { 14, 15 } },
    };

    mGameState.protag = new Entity(
        { mOrigin.x, mOrigin.y },
        { 100.0f, 100.0f },
        "assets/game/Robot_Ness.png",
        { 1.0f, 16.0f },
        animationAtlas,
        PLAYER
    );

    mGameState.protag->setColliderDimensions({ 60.0f, 60.0f });
    mGameState.protag->setFrameSpeed(8);

    mMetaton = new Entity(
        { mOrigin.x +200, mOrigin.y - 90.0f },
        { 80.0f, 80.0f },
        "assets/game/metaton.png",
        NPC
    );
    mMetaton->setStatic(true);

    mZsaber = new Entity(
        { mOrigin.x - 1850.0f, mOrigin.y + 150.0f },
        { 96.0f, 96.0f },
        "assets/game/Zsaber.png",
        NPC
    );
    mZsaber->setStatic(true);

    mProhobot = new Entity(
        { mOrigin.x - 200.0f, mOrigin.y -90.0f },
        { 80.0f, 108.0f },
        "assets/game/prohobot.png",
        NPC
    );
    mProhobot->setStatic(true);

    mProhobot2 = new Entity(
        { mOrigin.x - 400.0f, mOrigin.y + 1000.0f },
        { 80.0f, 108.0f },
        "assets/game/prohobot_gray.png",
        NPC
    );
    mProhobot2->setStatic(true);
    mProhobot2->deactivate();

    mNeo = new Entity(
        { mOrigin.x, mOrigin.y - 1500.0f },
        { 160.0f, 240.0f },
        "assets/game/NEO.png",
        NPC
    );
    mNeo->setStatic(true);

    mGameState.map = new Map(
        LEVEL_WIDTH, LEVEL_HEIGHT,
        LEVEL_DATA,
        "assets/game/tilesets.png",
        64.0f,
        16, 16,
        mOrigin,
        { 1, 2, 3, 10, 61, 64, 85, 129, 130, 131, 145, 146, 161, 189, 190, 204, 220 }
    );
}

void Dungeon::update(float deltaTime)
{
    int zsaberCount = (mZsaber && mZsaber->isActive()) ? 1 : 0;
    mGameState.protag->update(
        deltaTime,
        nullptr,
        mGameState.map,
        mZsaber,
        zsaberCount
    );
    if (mProhobot)  mGameState.protag->collideWith(mProhobot);
    if (mProhobot2) mGameState.protag->collideWith(mProhobot2);
    if (mNeo)       mGameState.protag->collideWith(mNeo);
    if (mMetaton)  mMetaton->update(deltaTime,  nullptr, nullptr, nullptr, 0);
    if (mZsaber)   mZsaber->update(deltaTime,   nullptr, nullptr, nullptr, 0);
    if (mProhobot)  mProhobot->update(deltaTime,  nullptr, nullptr, nullptr, 0);
    if (mProhobot2) mProhobot2->update(deltaTime, nullptr, nullptr, nullptr, 0);
    if (mNeo)       mNeo->update(deltaTime,       nullptr, nullptr, nullptr, 0);
}

void Dungeon::render()
{
    ClearBackground(ColorFromHex(mBGColourHexCode));

    if (mGameState.map) mGameState.map->render();
    if (mMetaton)  mMetaton->render();
    if (mZsaber)   mZsaber->render();
    if (mProhobot)  mProhobot->render();
    if (mProhobot2) mProhobot2->render();
    if (mNeo)       mNeo->render();
    mGameState.protag->render();
}

void Dungeon::shutdown()
{
    delete mGameState.protag;
    mGameState.protag = nullptr;

    delete mGameState.map;
    mGameState.map = nullptr;

    delete mMetaton;
    mMetaton = nullptr;

    delete mZsaber;
    mZsaber = nullptr;

    delete mProhobot;
    mProhobot = nullptr;

    delete mProhobot2;
    mProhobot2 = nullptr;

    delete mNeo;
    mNeo = nullptr;
}

void Dungeon::switchToMap2()
{
    delete mGameState.map;
    mGameState.map = new Map(
        LEVEL_WIDTH, LEVEL_HEIGHT,
        LEVEL_DATA_2,
        "assets/game/tilesets.png",
        64.0f,
        16, 16,
        mOrigin,
        { 1, 2, 3, 10, 61, 64, 85, 129, 130, 131, 145, 146, 161, 189, 190, 204, 220 }
    );

    if (mProhobot2) mProhobot2->activate();
}
